import{_ as t,o as a,c as i,ae as r}from"./chunks/framework.DeBUZsJm.js";const c=JSON.parse('{"title":"Astrogram Features","description":"","frontmatter":{},"headers":[],"relativePath":"astrogram-features.md","filePath":"astrogram-features.md","lastUpdated":1775513914000}'),s={name:"astrogram-features.md"};function l(n,e,o,u,d,p){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="astrogram-features" tabindex="-1">Astrogram Features <a class="header-anchor" href="#astrogram-features" aria-label="Permalink to &quot;Astrogram Features&quot;">​</a></h1><p>Astrogram is not only a plugin host. Part of the project lives directly inside the desktop client.</p><h2 id="settings-home" tabindex="-1">Settings home <a class="header-anchor" href="#settings-home" aria-label="Permalink to &quot;Settings home&quot;">​</a></h2><p>Astrogram-specific client functionality is intended to live under the Astrogram settings area instead of being scattered through unrelated Telegram settings pages.</p><p>Current direction:</p><ul><li>Astrogram entry point in settings</li><li>plugin entry point</li><li>links and support entry points</li><li>privacy and experimental desktop-native features</li></ul><h2 id="client-side-features-vs-plugin-side-features" tabindex="-1">Client-side features vs plugin-side features <a class="header-anchor" href="#client-side-features-vs-plugin-side-features" aria-label="Permalink to &quot;Client-side features vs plugin-side features&quot;">​</a></h2><p>Some things belong in plugins:</p><ul><li>optional visual experiments</li><li>network-backed helpers</li><li>user-installable utilities</li><li>rapidly changing prototypes</li></ul><p>Some things belong in the client:</p><ul><li>anti-recall behavior inside the message list</li><li>ghost mode and deeper privacy hooks</li><li>local premium UI overrides</li><li>settings shells and global branded entry points</li></ul><h2 id="why-this-split-matters" tabindex="-1">Why this split matters <a class="header-anchor" href="#why-this-split-matters" aria-label="Permalink to &quot;Why this split matters&quot;">​</a></h2><p>If a feature needs:</p><ul><li>MTProto/session-level interception</li><li>message rendering changes</li><li>global navigation changes</li><li>guaranteed startup behavior</li></ul><p>it is usually a client feature, not a plugin feature.</p><h2 id="current-built-in-focus-areas" tabindex="-1">Current built-in focus areas <a class="header-anchor" href="#current-built-in-focus-areas" aria-label="Permalink to &quot;Current built-in focus areas&quot;">​</a></h2><ul><li>branded Astrogram settings home</li><li>plugin manager UX</li><li>safe mode and recovery handling</li><li>anti-recall data retention and tooling</li><li>deeper privacy toggles</li></ul><h2 id="relationship-to-donor-projects" tabindex="-1">Relationship to donor projects <a class="header-anchor" href="#relationship-to-donor-projects" aria-label="Permalink to &quot;Relationship to donor projects&quot;">​</a></h2><p>Astrogram can borrow ideas from AyuGram and other Telegram forks, but desktop-native integration still needs to fit the Astrogram client architecture and plugin runtime.</p><p>That is why some ideas are shipped as built-in features while others remain plugins or examples first.</p>',20)])])}const g=t(s,[["render",l]]);export{c as __pageData,g as default};
